```javascript
class Router {
  constructor() {
    this.routes = new Map();
  }

  add(method, pattern, handler) {
    if (!this.routes.has(method)) {
      this.routes.set(method, []);
    }

    const routes = this.routes.get(method);
    const route = {
      pattern: this.parsePattern(pattern),
      handler: handler
    };

    routes.push(route);
  }

  parsePattern(pattern) {
    const segments = pattern.split('/');
    const regexParts = [];
    const params = [];

    for (let i = 0; i < segments.length; i++) {
      const segment = segments[i];
      if (segment.startsWith(':')) {
        const paramName = segment.substring(1);
        params.push(paramName);
        regexParts.push('([^/]+)');
      } else if (segment) {
        regexParts.push(this.escapeRegex(segment));
      }
    }

    const regexString = '^' + regexParts.join('/') + '$';
    return {
      regex: new RegExp(regexString),
      params: params
    };
  }

  escapeRegex(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  match(method, path) {
    if (!this.routes.has(method)) {
      return null;
    }

    const routes = this.routes.get(method);

    for (const route of routes) {
      const match = path.match(route.pattern.regex);

      if (match) {
        const params = {};
        for (let i = 0; i < route.pattern.params.length; i++) {
          params[route.pattern.params[i]] = match[i + 1];
        }

        return {
          handler: route.handler,
          params: params
        };
      }
    }

    return null;
  }
}
