```javascript
function parseTemplate(template, data) {
  // Handle variable substitution
  function substituteVariables(str) {
    return str.replace(/{{([^}]+)}}/g, (match, variablePath) => {
      const keys = variablePath.split('.');
      let value = data;

      for (let i = 0; i < keys.length; i++) {
        if (value === null || value === undefined) {
          return '';
        }
        value = value[keys[i]];
      }

      return value !== null && value !== undefined ? String(value) : '';
    });
  }

  // Handle conditional blocks
  function handleIfBlocks(str) {
    return str.replace(/{{#if ([^}]+)}}([\s\S]*?){{\/if}}/g, (match, condition, content) => {
      const keys = condition.split('.');
      let value = data;

      for (let i = 0; i < keys.length; i++) {
        if (value === null || value === undefined) {
          return '';
        }
        value = value[keys[i]];
      }

      return value ? substituteVariables(content) : '';
    });
  }

  // Handle iteration blocks
  function handleEachBlocks(str) {
    return str.replace(/{{#each ([^}]+)}}([\s\S]*?){{\/each}}/g, (match, arrayPath, content) => {
      const keys = arrayPath.split('.');
      let array = data;

      for (let i = 0; i < keys.length; i++) {
        if (array === null || array === undefined) {
          return '';
        }
        array = array[keys[i]];
      }

      if (!Array.isArray(array)) {
        return '';
      }

      return array.map(item => {
        // Create a temporary data object with 'this' pointing to the current item
        const tempData = { ...data, this: item };
        return substituteVariables(content).replace(/{{this\.([^}]+)}}/g, (match, prop) => {
          if (item && typeof item === 'object') {
            return String(item[prop]) || '';
          }
          return '';
        });
      }).join('');
    });
  }

  // Process in order: each blocks first, then if blocks, then variables
  let result = template;

  // Handle each blocks first (they might contain other blocks)
  while (result.includes('{{#each')) {
    result = handleEachBlocks(result);
  }

  // Then handle if blocks
  while (result.includes('{{#if')) {
    result = handleIfBlocks(result);
  }

  // Finally handle variable substitution
  result = substituteVariables(result);

  return result;
}

