def topological_sort(graph):
    # Count in-degrees for each node
    in_degree = {node: 0 for node in graph}

    # Calculate in-degrees
    for node in graph:
        for dependency in graph[node]:
            if dependency not in in_degree:
                in_degree[dependency] = 0
            in_degree[dependency] += 1

    # Find all nodes with no dependencies (in-degree = 0)
    queue = [node for node in in_degree if in_degree[node] == 0]

    result = []

    while queue:
        # Remove a node with no remaining dependencies
        current = queue.pop(0)
        result.append(current)

        # For each dependent of the current node, reduce its in-degree
        for node in graph:
            if current in graph[node]:
                in_degree[node] -= 1
                # If in-degree becomes 0, add to queue
                if in_degree[node] == 0:
                    queue.append(node)

    # Check if we processed all nodes (no cycles)
    if len(result) != len(in_degree):
        raise ValueError('cycle detected')

    return result

