```rust
fn longest_common_prefix(strs: &[&str]) -> String {
    // Handle empty array
    if strs.is_empty() {
        return String::new();
    }

    // Handle single string
    if strs.len() == 1 {
        return strs[0].to_string();
    }

    // Find the minimum length among all strings
    let min_length = strs.iter().map(|s| s.len()).min().unwrap_or(0);

    // Compare characters at each position
    let mut prefix_length = 0;

    for i in 0..min_length {
        let current_char = strs[0].chars().nth(i).unwrap();

        // Check if all strings have the same character at position i
        if strs.iter().all(|s| s.chars().nth(i) == Some(current_char)) {
            prefix_length += 1;
        } else {
            break;
        }
    }

    // Return the prefix up to prefix_length
    strs[0][..prefix_length].to_string()
}

fn main() {
    println!("{}", longest_common_prefix(&["flower", "flow", "flight"]));
    println!("{}", longest_common_prefix(&["dog", "racecar", "car"]));
    println!("{}", longest_common_prefix(&["interspecies", "interstellar", "interstate"]));
    println!("{}", longest_common_prefix(&["alone"]));
    println!("'{}'", longest_common_prefix(&[]));
}
