import { shallowReactive } from 'vue'

const MAX_LOADED = 10

export function useSessionState() {
  // Use shallowReactive to preserve ref reactivity in map values
  const stateMap = shallowReactive(new Map())
  const lruOrder = []

  // Fallback state for when no sessionId is provided
  const fallbackState = {
    messages: [],
    streaming: false,
    error: null
  }

  const getState = (sessionId) => {
    if (!sessionId) {
      return fallbackState
    }

    // If session already exists, update LRU order
    if (stateMap.has(sessionId)) {
      // Remove from current position
      const index = lruOrder.indexOf(sessionId)
      if (index > -1) {
        lruOrder.splice(index, 1)
      }
      // Add to end (most recently used)
      lruOrder.push(sessionId)
      return stateMap.get(sessionId)
    }

    // Create new session state
    const newState = {
      messages: ref([]),
      streaming: ref(false),
