      const index = lruOrder.indexOf(sessionId)
      if (index > -1) {
        lruOrder.splice(index, 1)
      }
      // Add to end (most recently used)
      lruOrder.push(sessionId)
      return stateMap.get(sessionId)
    }

    // Create new session state
    const newState = {
      messages: ref([]),
      streaming: ref(false),
      error: ref(null)
    }

    stateMap.set(sessionId, newState)

    // Update LRU order
    lruOrder.push(sessionId)

    // Check if we need to evict oldest session
    if (lruOrder.length > MAX_LOADED) {
      const oldestSessionId = lruOrder.shift()
      stateMap.delete(oldestSessionId)
    }

    return newState
  }

  return {
    getState
  }
